final case class ConfigSetting(path: String, value: String)

final case class ConfigParseResult(settings: List[ConfigSetting])

final class XmlConfigService {
  def parseConfigXml(xml: String): Either[String, ConfigParseResult] = {
    Try(XML.loadString(xml)) match {
      case Success(root) =>
        Right(ConfigParseResult(extractSettings(root)))
      case Failure(e) =>
        Left(s"Failed to parse XML configuration: ${e.getMessage}")
    }
  }

  private def extractSettings(node: Node, currentPath: String = ""): List[ConfigSetting] = {
    val nextPath = if (currentPath.isEmpty) node.label else s"$currentPath/${node.label}"

    val attributes = node.attributes.asAttrMap.toList.map { case (k, v) =>
      ConfigSetting(s"$nextPath/@$k", v)
    }

    val children = node.child.collect {
      case e: Elem => extractSettings(e, nextPath)
    }.flatten

    val textValue = node.child.collect {
      case n if n.text.trim.nonEmpty && n.isAtom => n.text.trim
    }.mkString(" ").trim

    val nodeValue =
      if (textValue.nonEmpty && node.child.forall(_.isInstanceOf[scala.xml.Text])) {
        List(ConfigSetting(nextPath, textValue))
      } else {
        Nil
      }

    attributes ++ nodeValue ++ children
  }
}

